// Aggregate order data for analysis
const orders = $input.all();

let totalRevenue = 0;
let orderCount = orders.length;
let productCounts = {};
let dailySales = {};

orders.forEach(order => {
  const orderData = order.json;

  // Calculate revenue
  totalRevenue += parseFloat(orderData.total_price || 0);

  // Track daily sales
  const date = orderData.created_at.split('T')[0];
  dailySales[date] = (dailySales[date] || 0) + parseFloat(orderData.total_price || 0);

  // Count products
  orderData.line_items?.forEach(item => {
    const productName = item.name;
    productCounts[productName] = (productCounts[productName] || 0) + item.quantity;
  });
});

// Get top 5 products
const topProducts = Object.entries(productCounts)
  .sort(([,a], [,b]) => b - a)
  .slice(0, 5)
  .map(([name, count]) => ({ name, quantity: count }));

// Calculate average order value
const avgOrderValue = orderCount > 0 ? (totalRevenue / orderCount).toFixed(2) : 0;

// Previous week for comparison (mock data - would typically come from sheets)
const previousWeekRevenue = totalRevenue * 0.95; // Simulated previous week

return {
  totalRevenue: totalRevenue.toFixed(2),
  orderCount,
  avgOrderValue,
  topProducts,
  dailySales,
  previousWeekRevenue: previousWeekRevenue.toFixed(2),
  revenueChange: (((totalRevenue - previousWeekRevenue) / previousWeekRevenue) * 100).toFixed(1)
};

